package com.mina.yuedu.network;
import com.mina.yuedu.model.*;import java.util.*;
public final class SourceParserTest {
 private static void ok(boolean v,String m){if(!v)throw new AssertionError(m);} private static void eq(Object a,Object b,String m){if(!Objects.equals(a,b))throw new AssertionError(m+": "+a+" != "+b);}
 public static void runAll(){String j="[{\"bookSourceName\":\"A😀\",\"bookSourceUrl\":\"https://a.com\",\"x\":1}]";SourceParser.ParseResult r=SourceParser.parseArray(j,7);eq(r.getRecords().size(),1,"rows");eq(r.getRecords().get(0).getOrder(),7,"order");eq(r.getRecords().get(0).getName(),"A😀","unicode");String h="<a href='/yuedu/shuyuan/json/id/1188.json'>下载</a>";List<String> u=SourceParser.discoverYckJsonUrls(h,"https://www.yckceo.com/x");eq(u.get(0),"https://www.yckceo.com/yuedu/shuyuan/json/id/1188.json","discover");SourceParser.ParseResult escaped=SourceParser.parseArray("[{\"bookSourceName\":\"E\",\"bookSourceUrl\":\"https://e.com\",\"rule\":\"a\\nb\"}]",0);eq(escaped.getRecords().size(),1,"escaped newline");eq(escaped.getRecords().get(0).getRaw().get("rule"),"a\nb","decoded newline");String hp="<a href=\"/yuedu/shuyuans/json/id/1193.json\">x</a>";eq(SourceParser.discoverYckJsonUrls(hp,"https://www.yckceo.com/").size(),1,"plural shuyuans");SourceParser.ParseResult bad=SourceParser.parseArray("{}",0);eq(bad.getInvalid().get(0).getKind(),InvalidSource.Kind.NOT_JSON_ARRAY,"not array");}
}
